  const BASE_PREMIUMS: Record<string, number> = {
    sword: 100,
    amulet: 60,
    staff: 80,
    potion: 40,
  };
  const COMPONENT_TYPES = ["rune", "moonstone"];
  const COMPONENT_BASE_PREMIUM = 25;
  const COMPONENT_BLOCK_SIZE = 3;
  const COMPONENT_BLOCK_BASE_PREMIUM = 60;

  if (items.length === 0) {
    return 5;
  }

  const mainItems = items.filter(item => !COMPONENT_TYPES.includes(item.type));
  const components = items.filter(item => COMPONENT_TYPES.includes(item.type));

  let premium = 0;

  for (const item of mainItems) {
    const basePremium = BASE_PREMIUMS[item.type];
    if (basePremium !== undefined) {
      premium += basePremium;
    }
  }

  const componentCount = components.length;
  if (componentCount > 0) {
    if (componentCount === COMPONENT_BLOCK_SIZE) {
      const largestBlockPremium = Math.max(...COMPONENT_TYPES.map(() => COMPONENT_BLOCK_BASE_PREMIUM));
      premium += largestBlockPremium;
    } else {
      premium += componentCount * COMPONENT_BASE_PREMIUM;
    }
  } else if (premium === 0 && items.length > 0) {
    premium = 5;
  }

  return premium;
}

