import { describe, it, expect, beforeEach } from "vitest";
import { quote, ClaimOffice, Scenario, Results } from "./claim-office.js";

describe("Claim Office", () => {
  describe("Quote - Base Premiums", () => {
    it("should return 5 G premium for empty item list -- only processing fee", () => {
      expect(quote({ yearsWithMHPCO: 0 }, [], 1)).toBe(5);
    });
    it("should return 100 G base premium for a sword -- 100 G base", () => {
      expect(quote({ yearsWithMHPCO: 0 }, [{ type: "sword" }], 1)).toBe(100);
    });
    it("should return 60 G base premium for an amulet -- 600 G value, 60 G base", () => {
      expect(quote({ yearsWithMHPCO: 0 }, [{ type: "amulet" }], 1)).toBe(60);
    });
    it("should return 80 G base premium for a staff -- 800 G value, 80 G base", () => {
      expect(quote({ yearsWithMHPCO: 0 }, [{ type: "staff" }], 1)).toBe(80);
    });
    it("should return 40 G base premium for a potion -- 400 G value, 40 G base", () => {
      expect(quote({ yearsWithMHPCO: 0 }, [{ type: "potion" }], 1)).toBe(40);
    });
    it("should return 25 G base premium for a single component -- 250 G value, 25 G base", () => {
      expect(quote({ yearsWithMHPCO: 0 }, [{ type: "rune" }], 1)).toBe(25);
    });
  });

  describe("Quote - Component Building Blocks", () => {
    it("should return 50 G base premium for 2 runes -- no block (block requires exactly 3)", () => {
      expect(quote({ yearsWithMHPCO: 0 }, [{ type: "rune" }, { type: "rune" }], 1)).toBe(50);
    });
    it("should return 60 G base premium for 3 runes -- building block applies", () => {
      expect(quote({ yearsWithMHPCO: 0 }, [{ type: "rune" }, { type: "rune" }, { type: "rune" }], 1)).toBe(60);
    });
    it("should return 100 G base premium for 4 runes -- no block (must be exactly 3)", () => {
      expect(quote({ yearsWithMHPCO: 0 }, [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }], 1)).toBe(100);
    });
    it("should return 175 G base premium for 7 runes -- 2 blocks (6) + 1 extra (25) = 175", () => {
      expect(quote({ yearsWithMHPCO: 0 }, [
        { type: "rune" }, { type: "rune" }, { type: "rune" },
        { type: "rune" }, { type: "rune" }, { type: "rune" },
        { type: "rune" }
      ], 1)).toBe(175);
    });
  });

  describe("Quote - Alike Components (Different Types)", () => {
    it("should return 75 G for 2 runes + 1 moonstone -- no block (different types)", () => {
      expect(quote({ yearsWithMHPCO: 0 }, [
        { type: "rune" }, { type: "rune" }, { type: "moonstone" }
      ], 1)).toBe(75);
    });
    it("should return 120 G for 3 runes + 3 moonstones -- two separate blocks", () => {
      expect(quote({ yearsWithMHPCO: 0 }, [
        { type: "rune" }, { type: "rune" }, { type: "rune" },
        { type: "moonstone" }, { type: "moonstone" }, { type: "moonstone" }
      ], 1)).toBe(120);
    });
  });

  describe("Quote - Cursed Modifier", () => {
    it("should add 50% surcharge for cursed sword -- 100 G base + 50 G surcharge = 150 G", () => {
      expect(quote({ yearsWithMHPCO: 0 }, [{ type: "sword", cursed: true }], 1)).toBe(150);
    });
    it("should add 50% surcharge for cursed amulet -- 60 G base + 30 G surcharge = 90 G", () => {
      expect(quote({ yearsWithMHPCO: 0 }, [{ type: "amulet", cursed: true }], 1)).toBe(90);
    });
    it("should not add surcharge for non-cursed item -- 60 G base amulet stays 60 G", () => {
      expect(quote({ yearsWithMHPCO: 0 }, [{ type: "amulet" }], 1)).toBe(60);
    });
  });

  describe("Quote - High Enchantment Modifier", () => {
    it("should add 30% surcharge for sword with enchantment 5 -- threshold check", () => {
      expect(quote({ yearsWithMHPCO: 0 }, [{ type: "sword", enchantment: 5 }], 1)).toBe(130);
    });
    it("should add 30% surcharge for sword with enchantment 7 -- high enchantment", () => {
      expect(quote({ yearsWithMHPCO: 0 }, [{ type: "sword", enchantment: 7 }], 1)).toBe(130);
    });
    it("should NOT add surcharge for sword with enchantment 4 -- below threshold", () => {
      expect(quote({ yearsWithMHPCO: 0 }, [{ type: "sword", enchantment: 4 }], 1)).toBe(100);
    });
    it("should apply both cursed and high-enchantment surcharges -- sword with enchantment 5 and cursed", () => {
      expect(quote({ yearsWithMHPCO: 0 }, [{ type: "sword", enchantment: 5, cursed: true }], 1)).toBe(180);
    });
  });

  describe("Quote - Customer History Modifiers", () => {
    it("should apply 20% loyalty discount for customer with 2 years -- threshold check", () => {
      expect(quote({ yearsWithMHPCO: 2 }, [{ type: "sword" }], 1)).toBe(85);
    });
    it("should apply 20% loyalty discount for customer with 3+ years", () => {
      expect(quote({ yearsWithMHPCO: 3 }, [{ type: "sword" }], 1)).toBe(85);
    });
    it("should NOT apply loyalty discount for customer with 1 year -- below threshold", () => {
      expect(quote({ yearsWithMHPCO: 1 }, [{ type: "sword" }], 1)).toBe(100);
    });
  });

  describe("Quote - First Insurance Surcharge", () => {
    it("should apply 10% first insurance surcharge to items in first quote", () => {
      expect(quote({ yearsWithMHPCO: 0 }, [{ type: "sword" }], 1)).toBe(110);
    });
  });

  describe("Quote - Follow-up Contract Discount", () => {
    it("should apply 15% discount for follow-up contracts -- second or later quote", () => {
      expect(quote({ yearsWithMHPCO: 2 }, [{ type: "sword" }], 2)).toBe(72.5);
    });
  });

  describe("Quote - Modifier Scope (Multi-item Policies)", () => {
    it("should apply cursed surcharge only to cursed sword -- not to amulet base premium", () => {
      expect(quote({ yearsWithMHPCO: 0 }, [{ type: "sword", cursed: true }, { type: "amulet" }], 1)).toBe(210);
    });
    it("should sum item base premiums before policy-wide modifiers -- sword + amulet base", () => {
      expect(quote({ yearsWithMHPCO: 0 }, [{ type: "sword" }, { type: "amulet" }], 1)).toBe(160);
    });
  });

  describe("Quote - Full Premium Calculation", () => {
    it("should return 165 G for newcomer with cursed sword -- 100 base + 50 curse + 10 first + 5 fee", () => {
      expect(quote({ yearsWithMHPCO: 0 }, [{ type: "sword", cursed: true }], 1)).toBe(165);
