    });
    it("should return 60 G base premium for 3 runes (block)", () => {
      expect(quote({ yearsWithMHPCO: 0 }, [{ type: "rune" }, { type: "rune" }, { type: "rune" }], 1)).toBe(65);
    });
    it("should return 100 G base premium for 4 runes", () => {
      expect(quote({ yearsWithMHPCO: 0 }, [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }], 1)).toBe(105);
    });
