      expect(quote({ yearsWithMHPCO: 0 }, [
        { type: "rune" }, { type: "rune" }, { type: "rune" },
        { type: "rune" }, { type: "rune" }, { type: "rune" },
        { type: "rune" }
      ], 1)).toBe(180);
    });
  });

  describe("Quote - Alike Components", () => {
    it("should return 75 G for 2 runes + 1 moonstone", () => {
      expect(quote({ yearsWithMHPCO: 0 }, [
        { type: "rune" }, { type: "rune" }, { type: "moonstone" }
