    it("should apply 10% first insurance surcharge", () => {
      expect(quote({ yearsWithMHPCO: 0 }, [{ type: "sword" }], 1)).toBe(115);
    });
  });

  describe("Quote - Follow-up Contract Discount", () => {
    it("should apply 15% discount for follow-up contracts", () => {
